const body = $input.first().json.body;
const entry = body?.entry?.[0];
const changes = entry?.changes?.[0];
const msg = changes?.value?.messages?.[0];
if (!msg) return [];
const contact = changes?.value?.contacts?.[0];
return [{
  json: {
    channel: 'whatsapp',
    sender_id: msg.from || 'unknown',
    sender_name: contact?.profile?.name || msg.from || 'unknown',
    body: msg.text?.body || msg.type || '[media]',
    raw_metadata: JSON.stringify({ wamid: msg.id, timestamp: msg.timestamp, type: msg.type }),
    status: 'unread'
  }
}];
